import{_ as i,o as e,c as a,ai as n,ui as t,uj as l,uk as r,ul as o}from"./chunks/framework.DIUhWiTt.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"notas/PortSwigger/5.Authentication vulnerabilities/4.Broken brute-force protection, IP block/4.Broken brute-force protection, IP block.md","filePath":"notas/PortSwigger/5.Authentication vulnerabilities/4.Broken brute-force protection, IP block/4.Broken brute-force protection, IP block.md"}'),p={name:"notas/PortSwigger/5.Authentication vulnerabilities/4.Broken brute-force protection, IP block/4.Broken brute-force protection, IP block.md"};function c(d,s,h,k,u,g){return e(),a("div",null,[...s[0]||(s[0]=[n('<p>Es muy probable que un ataque de fuerza bruta implique muchos intentos fallidos antes de que el atacante logre comprometer una cuenta. Lógicamente, la protección de fuerza bruta gira en torno a intentar que sea lo más difícil posible automatizar el proceso y ralentizar el ritmo al que un atacante puede intentar iniciar sesión. Las dos formas más comunes de prevenir los ataques de fuerza bruta son:</p><p>Bloquear la cuenta a la que el usuario remoto está intentando acceder si realiza demasiados intentos de inicio de sesión fallidos Bloquear la dirección IP del usuario remoto si realiza demasiados intentos de inicio de sesión en rápida sucesión Ambos enfoques ofrecen diversos grados de protección, pero ninguno es invulnerable, especialmente si se implementan utilizando una lógica errónea.</p><p>Por ejemplo, a veces puede ocurrir que se bloquee tu IP si no consigues conectarte demasiadas veces. En algunas implementaciones, el contador del número de intentos fallidos se reinicia si el propietario de la IP se conecta con éxito. Esto significa que un atacante simplemente tendría que iniciar sesión en su propia cuenta cada pocos intentos para evitar que se alcance este límite.</p><p>En este caso, la mera inclusión de sus propias credenciales de inicio de sesión a intervalos regulares a lo largo de la lista de palabras es suficiente para hacer que esta defensa sea prácticamente inútil.</p><h2 id="lab" tabindex="-1">LAB <a class="header-anchor" href="#lab" aria-label="Permalink to “LAB”">​</a></h2><p><img src="'+t+`" alt="20250803190712.png"></p><p>Al intentar dos veces y luego enviar la tercera solicitud el servidor nos enía un mensaje <code>You have made too many incorrect login attemtps. please try again in 1 minute(s)</code> el cual indica que nuestra IP ha sido bloqueada por 1 minuto por intento de logins fallidos.</p><p>Para bypaser esto, lo que haremos será intentar dos vez con el usuario <code>carlos</code> y luego usar las credenciales de wiener y hacer un login exitoso, haciendo que el servidor no bloquee nuestra dirección IP</p><ul><li><a href="https://portswigger.net/web-security/authentication/auth-lab-passwords" target="_blank" rel="noreferrer">https://portswigger.net/web-security/authentication/auth-lab-passwords</a></li></ul><p>Para ello debemos construir una lista de credenciales en el siguiente formato:</p><div class="language-c"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[credencial de wiener]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">password1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">password2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[credencial de wiener]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">password3</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">password4</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[credencial de wiener]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...</span></span></code></pre></div><p>También debemos tener una lista de usuarios en el siguiente formato:</p><div class="language-c"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">wiener</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">carlos</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">carlos</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">wiener</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">carlos</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">carlos</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">wiener</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">carlos</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">carlos</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...</span></span></code></pre></div><p>Para construir nuestra lista de contraseñas usaremos el siguiente comando:</p><div class="language-c"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">❯ awk </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;NR%2==0{print $0 RS &quot;peter&quot;; next} {print}&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> password.txt </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> password</span></span></code></pre></div><ul><li><p><code>NR%2==0</code> → cuando el número de línea es par (cada dos líneas).</p></li><li><p><code>{print $0 RS &quot;carlos&quot;; next}</code> → imprime la línea actual y luego agrega <code>&quot;carlos&quot;</code> en la siguiente línea.</p></li><li><p><code>{print}</code> → para las demás líneas, imprime normal.</p></li><li><p><code>RS</code> → separador de registros (salto de línea).</p></li><li><p><code>&gt; output.txt</code> → guarda el resultado en otro archivo.</p></li></ul><p>Y para la lista de usuarios usaremos un for con con 50 repeticiones</p><div class="language-c"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">❯ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> i in {</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">1..50</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">do</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> printf </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;carlos</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">carlos</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">wiener</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; done </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> users</span></span></code></pre></div><p>Una vez con nuestras wordlist, enviaremos la peticion al <code>intruder</code> y mediante un ataque de <code>Pitchfork attack</code> añadiremos las dos listas</p><p><img src="`+l+'" alt="20250803222504.png"></p><p>Además configuraremos el numero de solicitudes que se envían en paralelo</p><p><img src="'+r+'" alt="20250803222838.png"></p><p>Luego iniciaremos el ataque, después de un tiempo obtendremos las credenciales para el usuario <code>carlos</code>.</p><p><img src="'+o+'" alt="20250803222916.png"></p><div class="language-c"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">username</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">carlos</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">password</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sunshine</span></span></code></pre></div>',25)])])}const b=i(p,[["render",c]]);export{m as __pageData,b as default};
